    for (int i = 0; i < prices.length; i++) {
        originalProfit += strategy[i] * prices[i];
    }

    int n = prices.length;
    long m = k / 2;
    long[] leftPart = new long[n];
    long[] rightPart = new long[n];

    for (int i = 0; i < n; i++) {
        leftPart[i] = (-strategy[i]) * prices[i];
        rightPart[i] = (1 - strategy[i]) * prices[i];
    }

    long[] prefixLeft = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixLeft[i + 1] = prefixLeft[i] + leftPart[i];
    }

    long[] prefixRight = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixRight[i + 1] = prefixRight[i] + rightPart[i];
    }

    long maxDelta = -Long.MAX_VALUE;
    for (int i = 0; i <= n - k; i++) {
        long sumLeft = prefixLeft[i + m] - prefixLeft[i];
        long sumRight = prefixRight[i + k] - prefixRight[i + m];
        long delta = sumLeft + sumRight;
        if (delta > maxDelta) {
            maxDelta = delta;
        }
    }

    return originalProfit + Math.max(0, maxDelta);
}
