        left_part[i] = -strategy[i] * prices[i];
        right_part[i] = (1 - strategy[i]) * prices[i];
    }

    long[] prefix_left = new long[n + 1];
    long[] prefix_right = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefix_left[i + 1] = prefix_left[i] + left_part[i];
        prefix_right[i + 1] = prefix_right[i] + right_part[i];
    }

    long max_delta = Long.MIN_VALUE;
    int max_i = n - (int) k;
